// CSD_RATIONALE_BEGIN
// This strategy starts with a few unconstrained steps to generate initial text,
// then switches to constrained decoding when it encounters a delimiter within the
// delimited window. It uses a counter to limit the number of unconstrained steps
// and ensures that the delimiter window is valid before switching to constrained mode.
// CSD_RATIONALE_END

invariant lm.ValidTokensIdsLogits();
invariant 0 <= stepsLeft <= maxSteps;
invariant |generated| + stepsLeft == maxSteps;
invariant helpers.ConstrainedWindowValid(generated);
decreases stepsLeft;

var stepCounter := 0;
var hasValid := false;

while stepsLeft > 0 && !parser.IsCompletePrefix(generated)
{
    if stepCounter < 5
    {
        var next, newSteps := helpers.UnconstrainedStep(prompt, generated, stepsLeft);
        generated := generated + [next];
        stepsLeft := newSteps;
        hasValid := exists token :: token in parser.ValidNextTokens(generated) && parser.ValidNextToken(generated, token);
        stepCounter := stepCounter + 1;
    }
    else if helpers.InsideDelimitedWindow(generated) && !parser.IsCompletePrefix(helpers.GetDelimitedContent(generated))
    {
        var next, newSteps := helpers.ConstrainedStep(prompt, generated, stepsLeft);
        generated := generated + [next];
        stepsLeft := newSteps;
        hasValid := exists token :: token in parser.ValidNextTokens(generated) && parser.ValidNextToken(generated, token);
    }
    else
    {
        generated := helpers.RollbackToValidPrefix(generated);
        stepsLeft := stepsLeft + 1; // Increment stepsLeft since we rolled back
    }
}

